// Format sellers with their available slots
const sellers = $input.first().json;
const slots = $input.last().json;

// Group slots by seller_uid
const slotsBySeller = {};
for (const slot of slots) {
  if (!slotsBySeller[slot.seller_uid]) {
    slotsBySeller[slot.seller_uid] = [];
  }
  slotsBySeller[slot.seller_uid].push({
    date: slot.available_date,
    time: slot.start_time,
    available: slot.is_available,
    slotId: slot.slot_id
  });
}

// Format response
const formattedSellers = sellers.map(seller => ({
  id: seller.user_uid,
  uid: seller.user_uid,
  name: seller.name,
  email: seller.email,
  phone: seller.phone,
  specialty: seller.specialty.split(',').map(s => s.trim()),
  location: {
    address: seller.location,
    city: seller.location.split(',')[0].trim()
  },
  rating: seller.rating || 5.0,
  capacity: seller.capacity_kg || 100,
  availableSlots: slotsBySeller[seller.user_uid] || []
}));

return { 
  json: {
    success: true,
    sellers: formattedSellers,
    total: formattedSellers.length
  }
};
